import { Request, Response } from 'express';
import { Status, Messages } from '../common/constants';

import { JobSite, IJobSite } from '../models/JobSite';
import { JobLocation } from '../models/JobLocation';
import * as Sentry from '@sentry/node';
import escapeStringRegexp from 'escape-string-regexp';
import { Types } from 'mongoose';

const hasValue = (value: any): boolean => value !== undefined && value !== null && `${value}`.trim() !== '';

const getCoordinateValue = (params: any, coordinate: 'lat' | 'long'): any => {
    const coordinates = params?.location?.coordinates ?? params?.coordinates;

    if (coordinate === 'lat') {
        return params?.location?.lat
            ?? params?.location?.latitude
            ?? params?.locationLat
            ?? params?.latitude
            ?? params?.lat
            ?? (Array.isArray(coordinates) ? coordinates[1] : undefined);
    }

    return params?.location?.long
        ?? params?.location?.lng
        ?? params?.location?.longitude
        ?? params?.locationLong
        ?? params?.longitude
        ?? params?.long
        ?? params?.lng
        ?? (Array.isArray(coordinates) ? coordinates[0] : undefined);
};

const buildLocation = (params: any): { type: 'Point', coordinates: number[] } | undefined => {
    const lat = getCoordinateValue(params, 'lat');
    const long = getCoordinateValue(params, 'long');

    if (!hasValue(lat) || !hasValue(long)) {
        return undefined;
    }

    const parsedLat = Number(lat);
    const parsedLong = Number(long);

    if (!Number.isFinite(parsedLat) || !Number.isFinite(parsedLong)) {
        return undefined;
    }

    return {
        type: 'Point',
        coordinates: [parsedLong, parsedLat]
    };
};

const buildAddress = (params: any): any | undefined => {
    const address = params?.address || {};
    const addressData: any = {
        street: address.street ?? params?.street,
        city: address.city ?? params?.city,
        state: address.state ?? params?.state,
        zipcode: address.zipcode ?? address.zipCode ?? params?.zipcode ?? params?.zipCode
    };

    Object.keys(addressData).forEach((key) => {
        if (addressData[key] === undefined) {
            delete addressData[key];
        }
    });

    return Object.keys(addressData).some((key) => hasValue(addressData[key])) ? addressData : undefined;
};

const getOwnerFields = (jobLocation: any): any => {
    const ownerFields: any = {};
    const customerId = jobLocation?.customerId
        ?? (Array.isArray(jobLocation?.customerIds) ? jobLocation.customerIds[0] : jobLocation?.customerIds);
    const homeOwner = jobLocation?.homeOwner ?? jobLocation?.homeOwnerId;

    if (customerId) {
        ownerFields.customerId = customerId;
    }

    if (homeOwner) {
        ownerFields.homeOwner = homeOwner;
    }

    return ownerFields;
};

const buildExactNameRegex = (name: string): RegExp => new RegExp(`^${escapeStringRegexp(name.trim())}$`, 'i');


export const get = async (req: Request, res: Response) => {
    const { id } = req.params;
    const { query: queryParams = {} } = req;
    const { customerId, homeOwnerId, locationId, isActive } = queryParams;

    console.log('Query Params:', queryParams);

    let query: {
        _id?: string;
        customerId?: string;
        locationId?: Types.ObjectId;
        homeOwner?: string;
        $or?: Array<{[key: string]: any}>;
        isActive?: boolean;
    } = {};

    if (id) {
        query = { _id: id };
    } else if (customerId && locationId) {
        query = { customerId, locationId: new Types.ObjectId(locationId) };
    } else if (homeOwnerId && locationId) {
        query = { homeOwner: homeOwnerId, locationId: new Types.ObjectId(locationId) };
    } else if (customerId && !homeOwnerId) {
        query = { customerId };
    } else if (customerId && homeOwnerId) {
        query = { $or: [{ customerId }, { homeOwner: homeOwnerId }] };
    } else if (homeOwnerId && !customerId) {
        query = { homeOwner: homeOwnerId };
    } else if (locationId) {
        query = { locationId: new Types.ObjectId(locationId) };
    } 

    switch (isActive) {
    case 'true':
    case true:
        query = {...query, $or: [...(query.$or || []), { isActive: true }, { isActive: { $exists: false } }] };
        break;
    case 'false':
    case false:
        query = {...query, isActive: false};
        break;
    default:
        // Retrieve all job sites
        break;
    }

    try {
        const jobSites = await JobSite.find(query).lean();
        res.status(Status.OK).json(jobSites);
    } catch (err) {
        console.error('Error in get JobSite:', err);
        res.status(Status.InternalError).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const create = async (req: Request, res: Response) => {
    const params = req.body || {};
    const { name, locationId } = params;
    const location = buildLocation(params);
    const address = buildAddress(params);

    // Validate required parameters
    const missingParams = [];
    if (!hasValue(name)) missingParams.push('name');
    if (!locationId) missingParams.push('locationId');

    if (missingParams.length > 0) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.status(400).json({ status: Status.Error, message });
    }

    if (!location && !address) {
        return res.status(400).json({ status: Status.Error, message: 'Either location or address is required.' });
    }

    try {
        // Find the job location
        const jobLocation = await JobLocation.findById(locationId, { customerId: 1, customerIds: 1, homeOwner: 1, homeOwnerId: 1 });

        if (!jobLocation) {
            return res.status(404).json({ status: Status.Error, message: 'Subdivision not found.' });
        }

        const duplicateJobSite = await JobSite.findOne({
            locationId,
            name: buildExactNameRegex(name)
        });

        if (duplicateJobSite) {
            return res.status(400).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
        }

        const jobSiteData: any = {
            name,
            locationId,
            ...getOwnerFields(jobLocation)
        };

        if (location) {
            jobSiteData.location = location;
        }

        if (address) {
            jobSiteData.address = address;
        }

        // Create the new job site
        const newJobSite: IJobSite = await JobSite.create(jobSiteData);

        // Update the job location with the new job site
        await JobLocation.findByIdAndUpdate(locationId, {
            $push: { jobSites: newJobSite._id }
        });

        return res.status(Status.OK).json(newJobSite);

    } catch (error) {
        Sentry.captureException(error);
        console.error('Error in create job site:', error);
        return res.status(500).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const update = async (req: Request, res: Response) => {
    const params = req.body || {};
    const { id } = req.params;
    const {
        name,
        isActive,
        locationId,
    } = params;

    const missingParams = [];
    if (!id) missingParams.push('id');
    const isMissingParams = missingParams.length > 0;

    if (isMissingParams) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.json({ status: Status.Error, message });
    }

    try {
        const jobSite = await JobSite.findById(id).exec();

        if (!jobSite) {
            return res.json({ status: Status.Error, message: 'Job Address not found.' });
        }

        const currentLocationId = locationId ?? jobSite.locationId;
        const updateData: any = {};

        if (hasValue(name)) {
            const currentName = jobSite.name || '';
            const isNameChanged = name.trim().toLowerCase() !== currentName.trim().toLowerCase();

            if (isNameChanged) {
                const duplicateJobSite = await JobSite.findOne({
                    _id: { $ne: id },
                    locationId: currentLocationId,
                    name: buildExactNameRegex(name)
                });

                if (duplicateJobSite) {
                    return res.status(400).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
                }
            }

            updateData.name = name;
